class Solution:
    def solveEquation(self, equation: str) -> str:
        left, right = equation.split('=')
        x, num = 0, 0
        sign, n = 1, 0
        for c in left + '+' + right:
            if c == '=':
                sign = -1
            elif c == '+':
                x += sign * n
                num += sign * n
                n = 0
            elif c == '-':
                x += sign * n
                num += sign * n
                sign = -1
                n = 0
            elif c == 'x':
                x += sign * (n if n else 1)
                n = 0
            else:
                n = n * 10 + int(c)
        if x == 0:
            return "Infinite solutions" if num == 0 else "No solution"
        return "x=" + str(-num // x)
